interface WatermarkBackgroundProps {
  step: string;
}

export function WatermarkBackground({ step }: WatermarkBackgroundProps) {
  let xml = DOG_LEFT_XML;

  if (step === 'q1' || step === 'q2' || step === 'q3' || step === 'qConcern') {
    xml = DOG_LEFT_XML;
  } else if (step === 'q4' || step === 'qOwner' || step === 'q5') {
    xml = DOG_RIGHT_XML;
  } else if (step === 'q6' || step === 'q7b' || step === 'q8') {
    xml = DOG_RESTING_XML;
  } else {
    xml = PETS_PLAY_XML;
  }

  // Boost the very faint watermark strokes so the artwork reads on the purple background
  xml = xml
    .replace(/rgba\(255, 255, 255, 0\.15\)/g, 'rgba(255, 255, 255, 0.3)')
    .replace(/opacity="0\.6"/g, 'opacity="1"');

  if (Platform.OS === 'web') {
    const webXml = xml.replace(
      '<svg ',
      '<svg preserveAspectRatio="xMidYMin slice" '
    );
    return (
      <View style={styles.container} pointerEvents="none">
        <div
          style={{ width: '100%', height: '100%' }}
          dangerouslySetInnerHTML={{ __html: webXml }}
        />
      </View>
    );
  }

  return (
    <View style={styles.container} pointerEvents="none">
      <SvgXml xml={xml} width="100%" height="100%" preserveAspectRatio="xMidYMin slice" />
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    ...StyleSheet.absoluteFillObject,
    zIndex: 0,
    opacity: 1,
    overflow: 'hidden',
  },
});
